// Pseudo online whitening resilient to missing channels
function updateWhitening(X, mask) {
  // X: channels x frames
  // mask: 1 if channel present, 0 if dropped
  const Xpresent = X.filter((row, idx) => mask[idx] === 1);
  const cov = computeCovariance(Xpresent);
  // add small jitter to diagonal for stability
  const W = inverseSqrt(cov + eps * I);
  return W;
}
```

